
from huggingface_hub import run_job
import os

token = open('/home/s1nn3r/.cache/huggingface/token').read().strip()
command = [
    'bash', '-c',
    "echo '' | base64 -d > eval_hf.py && "
    "uv pip install --python /opt/venv/bin/python 'huggingface-hub<1.0' openenv-core fastmcp vllm "
    "git+https://huggingface.co/spaces/s1nn3rx69/recall-env && "
    "python eval_hf.py"
]

print("Submitting EVAL job...")
job = run_job(
    image='unsloth/unsloth:latest',
    command=command,
    secrets={'HF_TOKEN': token},
    flavor='a10g-small',
    namespace='s1nn3rx69',
)
print(f"Job launched: {job.job_id}")
print(f"https://huggingface.co/jobs/s1nn3rx69/{job.job_id}")
